//$Id$
//datalabel-content.js
import { Registry } from '../core/zc-registry';
import { validateNullVal, invokeFunction, isArray, defined, getPropVal, getDepth } from '../utils/zcutils';
import { isMultiPieChartType } from '../events/events-utils';
import { DATALABELS_LABELTYPE, STACKLABELS_LABELTYPE } from './labeltype-constants';
import { X_SHOWAS, Y_SHOWAS, Z_SHOWAS, PERCENT_SHOWAS, SPLITPERCENT_SHOWAS, MAXPERCENT_SHOWAS, GEO_SHOWAS, LEVEL_SHOWAS } from './showas-constants';
import { DataProcessor } from '../core/data-processor';
import { getFormattedValue, getFormattedValueByPercent } from '../formatter/formatter';
import { getTspanTemplate } from './tspan-utils';
import { NULL, UNDEFINED } from '../core/zc-constants';
// import { getStackedTotal } from '../core/data-processor/stackedTotal';
import { getAxisObject } from '../axis/axisutils';
import { getChartTypeByIndex, isMultiColorChart } from '../core/charttype-helpers';
import { getRendererIndex } from '../core/data-parser';
import { getRawColor } from '../utils/colorutils';
import { SANKEY_CHARTNAME } from '../core/chartname-constants';
import { stack } from '../core/main-zc-init';

export function dataLabelTextContent(chartObj, rp, conf, type = 'datalabels', total, seriespos = 0, yrangePos, paneid) {
    var yColumn = (chartObj.seriesdata[seriespos] && chartObj.seriesdata[seriespos].yaxiscolumnorder) || [0, 0], //We need the yaxis order and column order. But, rp.yaxiscolumnorder - returns only the yaxis order
        cType = getChartTypeByIndex(chartObj, paneid, seriespos),
        dataProcessorHelpers = DataProcessor.helpers,
        dataObject = chartObj.dataObject,
        columns = chartObj.dataSplicer.getColumns(),
        isGeoMap = chartObj.isGeoMap;

    rp = rp || {
        stacked: false,
        commonPlotOptions: chartObj.systemConf.chart.plot.plotoptions[cType.name],
        yaxiscolumnorder: dataProcessorHelpers.getParsedYAxisOrder(yColumn)
    };
    var dataset = chartObj.dataset,
        yaxiscolumnorder = rp.yaxiscolumnorder,
        stacked = rp.stacked,
        yscale = rp.yscale,
        isBubblePie = isMultiPieChartType(cType.value),
        piedataindex = validateNullVal(rp.commonPlotOptions.dataindex, 3),
        rendererIndex = getRendererIndex({ paneid }, chartObj, 0),
        getProcessedNodeFunc = chartObj.renderer[rendererIndex] && chartObj.renderer[rendererIndex].getProcessedNode,
        labelMeta = chartObj.dataSplicer.getEncode().label,
        labelIndex = labelMeta && labelMeta[0],
        hasLabelIndex = type === DATALABELS_LABELTYPE && defined(labelIndex),
        isStackLabel = type == STACKLABELS_LABELTYPE,
        showAs = hasLabelIndex ? (columns[labelIndex] ? `{{val(${labelIndex})}}` : labelIndex.toString()) : conf.showAs,
        isShowAsDefined =
            [X_SHOWAS, Y_SHOWAS, Z_SHOWAS, PERCENT_SHOWAS, SPLITPERCENT_SHOWAS, MAXPERCENT_SHOWAS, GEO_SHOWAS, LEVEL_SHOWAS].indexOf(showAs) != -1,
        hasPercentShowAs = [PERCENT_SHOWAS, SPLITPERCENT_SHOWAS, MAXPERCENT_SHOWAS].indexOf(showAs) != -1,
        hasShowAsFunction = typeof showAs === 'function' || typeof window[showAs] === 'function',
        datatype,
        formatConf,
        formattingFunc,
        newShowAs;

    /**
     * #ZC2050
     * in case of any custom behavior we use the base scale for y axis
     * since after applying zoom or brush the domain may change
     */
    if (chartObj.renderVisiblePointsOnly && !chartObj.isGeoMap) {
        yscale = getAxisObject(chartObj, 'y', yaxiscolumnorder).baseScale || yscale;
    }

    if (!isShowAsDefined && !hasShowAsFunction) {
        newShowAs = getTspanTemplate(showAs);
    }

    if (!hasLabelIndex) {
        var axisType = hasLabelIndex
            ? 'label'
            : showAs == X_SHOWAS
            ? X_SHOWAS
            : showAs == Z_SHOWAS && defined(dataset.zidx)
            ? Z_SHOWAS
            : isGeoMap
            ? GEO_SHOWAS
            : showAs == LEVEL_SHOWAS || chartObj.dataObject.isLevelAxisCategory ? LEVEL_SHOWAS 
            : Y_SHOWAS;
        datatype = columns[dataset.getColumnIdx(axisType, yColumn)].datatype;
        formatConf = dataset.getColumn(axisType, yColumn)[datatype];
        formattingFunc = hasPercentShowAs ? getFormattedValueByPercent : getFormattedValue;

        if (isBubblePie && !hasShowAsFunction && hasPercentShowAs) {
            var col = columns.filter(function(c) {
                return c.dataindex === piedataindex;
            })[0];
            col = defined(col) ? col : dataset.getColumnIdx(axisType, yColumn);
            datatype = col.datatype;
            formatConf = col[datatype];
        }
    }

    const isSankeyChart = cType.name === SANKEY_CHARTNAME;
    
    var textContent = function(dt, itemIndex = 0, bound) {
        var d = isStackLabel ? dt[1] : dt;
        var node = dataObject.isHierarchy && getProcessedNodeFunc && getProcessedNodeFunc(d);

        if (isSankeyChart && d._type == 'node' && !hasLabelIndex) {
            if (chartObj.isLevelAxisCategory) {
                let levelindex = getDepth(d.level) - 1;
                datatype = columns[dataset.getColumnIdx('level', levelindex)].datatype;
                formatConf = dataset.getColumn('level', levelindex)[datatype];
            } else {
                datatype = columns[dataset.getColumnIdx(d._format || 'x', [0, d._axisOrder])].datatype;
                formatConf = dataset.getColumn(d._format || 'x', [0, d._axisOrder])[datatype];
                const hasCustomFormat = getPropVal(formatConf, "format.customFormat");
                if (hasCustomFormat) {
                    return dataset.getX(d);     // return point value for sankey node
                }
            }
            d = d.original || d;
        }
        if (isShowAsDefined) {
            var value = NULL;
            switch (showAs) {
                case PERCENT_SHOWAS:
                case SPLITPERCENT_SHOWAS:
                case MAXPERCENT_SHOWAS:
                    var t = total,
                        v = isStackLabel
                            ? d
                            : stacked || dataObject.isPercentChart
                            ? d.y
                            : isBubblePie
                            ? d[piedataindex]
                            : (node && node.children && node.value) || d.value || dataset.getY(d, yaxiscolumnorder, yrangePos);

                    if (stacked && !dataObject.isPercentChart && type == DATALABELS_LABELTYPE) {
                        t = stack.getStackedTotal(chartObj, seriespos, d, showAs);
                    } else if (typeof total === 'function') {
                        t = total(d, showAs);
                    } else if (!defined(t)) {
                        if (showAs === MAXPERCENT_SHOWAS || !yscale) {
                            var domain = dataObject.ZC_BAR_getRangeY(yaxiscolumnorder);
                            t = v < 0 && v >= domain[0] ? -domain[0] : domain[1];
                        } else {
                            t = (yscale.originalDomain || yscale.domain())[1];
                        }
                    }

                    value = (v / t) * 100 || 0; //if t=0 and v=0, the 'value' holds NaN
                    break;
                case X_SHOWAS:
                    value = !(node && node.children) ? dataset.getActualX(d) : UNDEFINED;
                    break;
                case Z_SHOWAS:
                    if (defined(dataset.zidx)) {
                        value = dataset.getZ(d);
                    }
                    break;
                case LEVEL_SHOWAS:
                    value = d[dataset.levelidx(-1)];
                    break;
                case GEO_SHOWAS:
                    value = dataset.getGeo(d);
                    break;
                default:
                    value = isStackLabel
                        ? d
                        : dataObject.isHierarchy
                        ? (node && node.children && node.value) || d.value || dataset.getY(d, yaxiscolumnorder)
                        : dataset.getY(d, yaxiscolumnorder, yrangePos);
            }
            return formattingFunc(formatConf, value, datatype, chartObj, type);
        } else if (hasShowAsFunction) {
            const coordinates = (chartObj.cache.coordinates = chartObj.cache.coordinates || {});
            const coordinate = coordinates[d._key] = {};
            try {
                const cp = chartObj.renderer[d.seriesIndex || 0].commonOption;
                coordinate.x = chartObj.dataObject.getTransRectValue('x', d, d.subSeriesIndex, 0, cp);
                coordinate.y = chartObj.dataObject.getTransRectValue('y', d, d.subSeriesIndex, 0, cp);
                coordinate.width = chartObj.dataObject.getTransRectValue('width', d, d.subSeriesIndex, 0, cp);
                coordinate.height = chartObj.dataObject.getTransRectValue('height', d, d.subSeriesIndex, 0, cp);
            } catch (e) {}
            
            return invokeFunction(showAs, dt, bound, chartObj, { coordinate });
        } else {
            let isMultiColoring = isMultiColorChart(cType.name, chartObj),
                color = isStackLabel ? NULL : getRawColor(chartObj, isMultiColoring ? itemIndex : seriespos, d, seriespos, paneid);

            return dataset.getCustomizedVal(
                chartObj,
                newShowAs,
                seriespos,
                NULL,
                NULL,
                d,
                type,
                color,
                textContent.contentType !== 'html',
                NULL,
                yrangePos
            );
        }
    };

    //Find the content type of the data labels
    textContent.contentType =
        !isShowAsDefined && (hasShowAsFunction || isArray(showAs) || showAs.indexOf('<tspan') != -1) ? 'html' : 'text';
    textContent.multiLine = textContent.contentType === 'html' && !hasShowAsFunction && isArray(showAs) && showAs.length > 1;
    textContent.hasShowAsFunction = hasShowAsFunction;
    return textContent;
}
Registry.setComponent('dataLabel.getContent', dataLabelTextContent);
